// neohive-smart-prompts.ts
// Generated by the neohive:enable-smart-prompts skill (the "smart-recall" feature),
// then ADAPTED for this benchmark's hosted NeoHive (Cloudflare Access) + OpenRouter.
//
// Faithful-setup note (Arm B = every NeoHive feature enabled): this is the optional
// smart-context layer that getting-started offers via enable-smart-prompts. It sits
// on top of the bundled neohive.ts (glob/grep nudge). On every qualifying prompt it:
//   1. rewrites the prompt into a good memory_recall query (small model, headless)
//   2. discovers the NeoHive MCP URL from opencode.json
//   3. calls memory_recall over HTTP JSON-RPC
//   4. filters to the 1-3 most relevant results (small model)
//   5. injects the filtered block as an extra text part on the user message
//
// Adaptations vs the stock template (documented for transparency/critique):
//   - callMemoryRecall sends Cloudflare Access service-token headers
//     (CF-Access-Client-Id/Secret) + an explicit User-Agent. NeoHive sits behind
//     Cloudflare; the CF WAF (Error 1010) blocks default/empty User-Agents, so a UA
//     is mandatory. Bearer NEOHIVE_TOKEN is still honored if present.
//   - The rewrite + filter steps call the OpenRouter chat API DIRECTLY (one HTTP
//     request each) instead of the stock template's nested `opencode run` headless
//     sub-agent. Behaviorally identical (same prompts, same model, same inject), but
//     the stock approach spawns a second/third full ~170MB opencode process per
//     prompt, which OOM-kills (exit 137) the agent when the SWE-bench container runs
//     under x86 emulation. A direct completion is a tiny fraction of the memory.
//   - MODEL is an OpenRouter model (the container has OPENROUTER_API_KEY).
//
// Env: NEOHIVE_SMART_DISABLED=1 disables the hook. NEOHIVE_SMART_MODEL overrides
// the rewriter model. OPENROUTER_API_KEY drives the rewrite/filter completions.

import type { Plugin } from "@opencode-ai/plugin"

// Scope auto-recall to the routed hive (NEOHIVE_HIVE) when set, so a project that
// holds several repos' hives can't leak another instance's code into this solve.
// Empty = cross-hive RRF (the default multi-repo behavior).
const HIVE = process.env.NEOHIVE_HIVE || ""
const MODEL = (process.env.NEOHIVE_SMART_MODEL || "openrouter/z-ai/glm-4.6").replace(/^openrouter\//, "")
const TRIGGER = "min_len"
const DISABLE_FLAG = "NEOHIVE_SMART_DISABLED"

export default (async ({ directory }) => {
  return {
    "chat.message": async (_input: any, output: any) => {
      try {
        if (process.env[DISABLE_FLAG] === "1") return
        if (!process.env.OPENROUTER_API_KEY) return

        const userText = output.parts
          .filter((p: any) => p.type === "text")
          .map((p: any) => p.text)
          .join("\n")
          .slice(0, 2000)

        if (TRIGGER === "min_len") {
          if (userText.length < 10) return
          if (userText.startsWith("/")) return
        }

        // Step 1: rewrite prompt into a recall query (direct OpenRouter completion)
        const rewritePrompt = `You are a query rewriter for a semantic memory system. Given a user prompt, produce a single-line search query that would retrieve relevant stored knowledge. Use affirmative domain terms, not questions. Output ONLY the query, no preamble. Prompt: ${userText}`
        const query = (await chatComplete(rewritePrompt))?.trim().slice(0, 400)
        if (!query) return

        // Step 2: discover MCP URL
        const mcpUrl = await discoverNeoHiveUrl(directory)
        if (!mcpUrl) return

        // Step 3: call memory_recall (through Cloudflare Access)
        const memoriesRaw = await callMemoryRecall(mcpUrl, query, HIVE || undefined)
        if (!memoriesRaw) return

        // Step 4: filter via small model (direct OpenRouter completion)
        const filterPrompt = `You are filtering memory_recall results for relevance to the user's actual prompt.\n\nUser prompt: ${userText}\nRewritten query: ${query}\n\nMemory results:\n${memoriesRaw}\n\nPick the 1-3 items most relevant to the user's prompt. If none are genuinely relevant, output exactly "IRRELEVANT". Otherwise output a compact markdown block.\n\nOutput only the block, no preamble.`
        const filtered = (await chatComplete(filterPrompt))?.trim().slice(0, 3000)
        if (!filtered || filtered === "IRRELEVANT") return

        // Step 5: inject as extra text part
        output.parts.unshift({
          type: "text",
          text: `NeoHive smart context (rewriter: ${MODEL}, hive: ${HIVE || "all"}):\n${filtered}`,
        } as any)
      } catch {
        // Never block the user's prompt on plugin failure.
      }
    },
  }
}) satisfies Plugin

async function chatComplete(prompt: string): Promise<string | undefined> {
  const key = process.env.OPENROUTER_API_KEY
  if (!key) return undefined
  try {
    const resp = await fetch("https://openrouter.ai/api/v1/chat/completions", {
      method: "POST",
      headers: { "Content-Type": "application/json", Authorization: `Bearer ${key}` },
      body: JSON.stringify({
        model: MODEL,
        messages: [{ role: "user", content: prompt }],
        max_tokens: 600,
        temperature: 0,
      }),
      signal: AbortSignal.timeout(20000),
    })
    const data = await resp.json()
    return data?.choices?.[0]?.message?.content
  } catch {
    return undefined
  }
}

async function discoverNeoHiveUrl(cwd: string): Promise<string | undefined> {
  const fs = await import("node:fs/promises")
  const path = await import("node:path")
  const candidates = [
    path.join(cwd, ".mcp.json"),
    path.join(cwd, "opencode.json"),
    path.join(cwd, "opencode.jsonc"),
    path.join(process.env.HOME || "", ".config/opencode/opencode.json"),
    path.join(process.env.HOME || "", ".config/opencode/opencode.jsonc"),
  ]
  for (const p of candidates) {
    try {
      const raw = await fs.readFile(p, "utf8")
      const stripped = raw.replace(/\/\/.*/g, "").replace(/\/\*[\s\S]*?\*\//g, "")
      const data = JSON.parse(stripped)
      const mcp = data.mcp || data.mcpServers || {}
      for (const [name, server] of Object.entries<any>(mcp)) {
        if (/neohive|hivemind/i.test(name) && server && typeof server.url === "string") {
          return server.url
        }
      }
    } catch {}
  }
  return undefined
}

async function callMemoryRecall(url: string, query: string, hive?: string): Promise<string | undefined> {
  const args: Record<string, unknown> = { query, limit: 8 }
  if (hive) args.hive = hive
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    "Accept": "application/json, text/event-stream",
    // CF WAF (Error 1010) blocks default/empty UAs — an explicit UA is mandatory.
    "User-Agent": "neohive-smart-prompts/0.1",
  }
  const cfId = process.env.NEOHIVE_CF_ACCESS_CLIENT_ID
  const cfSecret = process.env.NEOHIVE_CF_ACCESS_CLIENT_SECRET
  if (cfId && cfSecret) {
    headers["CF-Access-Client-Id"] = cfId
    headers["CF-Access-Client-Secret"] = cfSecret
  }
  if (process.env.NEOHIVE_TOKEN) headers["Authorization"] = `Bearer ${process.env.NEOHIVE_TOKEN}`
  try {
    const resp = await fetch(url, {
      method: "POST",
      headers,
      body: JSON.stringify({ jsonrpc: "2.0", id: 1, method: "tools/call", params: { name: "memory_recall", arguments: args } }),
      signal: AbortSignal.timeout(8000),
    })
    const raw = await resp.text()
    let payload = raw
    for (const line of raw.split("\n")) {
      if (line.startsWith("data: ")) { payload = line.slice(6); break }
    }
    const data = JSON.parse(payload)
    const contents = data?.result?.content ?? []
    const texts = contents.filter((c: any) => c?.type === "text").map((c: any) => c.text)
    const combined = texts.join("\n")
    if (combined && !combined.includes("No relevant memories found")) return combined.slice(0, 6000)
  } catch {}
  return undefined
}
